  1	import React, { FC, useState } from 'react';
  2	import { Trans } from 'react-i18next';
  3	import { useNMStateTranslation } from 'src/utils/hooks/useNMStateTranslation';
  4	import { Updater } from 'use-immer';
  5	
  6	import { Button, Form, FormGroup, Popover, Text, TextInput } from '@patternfly/react-core';
  7	import { HelpIcon, PlusCircleIcon } from '@patternfly/react-icons';
  8	import {
  9	  InterfaceType,
 10	  NodeNetworkConfigurationInterface,
 11	  V1NodeNetworkConfigurationPolicy,
 12	} from '@types';
 13	
 14	import NodeSelectorModal from '../NodeSelectorModal/NodeSelectorModal';
 15	
 16	import ApplySelectorCheckbox from './ApplySelectorCheckbox';
 17	import PolicyFormOVSBridgeMapping from './PolicyFormOVSBridgeMapping';
 18	import PolicyInterfacesExpandable from './PolicyInterfaceExpandable';
 19	import { isOVSBridgeExisting } from './utils';
 20	
 21	import './policy-form.scss';
 22	
 23	type PolicyFormProps = {
 24	  policy: V1NodeNetworkConfigurationPolicy;
 25	  setPolicy: Updater<V1NodeNetworkConfigurationPolicy>;
 26	  createForm?: boolean;
 27	  formId?: string;
 28	};
 29	
 30	const PolicyForm: FC<PolicyFormProps> = ({ policy, setPolicy, createForm = false, formId }) => {
 31	  const { t } = useNMStateTranslation();
 32	  const [modalOpen, setModalOpen] = useState(false);
 33	  const isOVSBridge = isOVSBridgeExisting(policy);
 34	
 35	  const onDescriptionChange = (newDescription: string) => {
 36	    setPolicy(({ metadata }) => {
 37	      if (!metadata.annotations) metadata.annotations = {};
 38	
 39	      metadata.annotations.description = newDescription;
 40	    });
 41	  };
 42	
 43	  const addNewInterface = () => {
 44	    setPolicy((draftPolicy) => {
 45	      if (!draftPolicy.spec?.desiredState?.interfaces) {
 46	        draftPolicy.spec.desiredState = {
 47	          interfaces: [] as NodeNetworkConfigurationInterface[],
 48	        };
 49	      }
 50	
 51	      draftPolicy.spec.desiredState.interfaces.unshift({
 52	        type: InterfaceType.LINUX_BRIDGE,
 53	        name: `interface-${draftPolicy.spec.desiredState.interfaces.length}`,
 54	        state: 'up',
 55	        bridge: {
 56	          options: {
 57	            stp: {
 58	              enabled: false,
 59	            },
 60	          },
 61	        },
 62	      } as NodeNetworkConfigurationInterface);
 63	    });
 64	  };
 65	
 66	  return (
 67	    <Form className="policy-form-content" id={formId}>
 68	      {createForm && (
 69	        <>
 70	          <NodeSelectorModal
 71	            isOpen={modalOpen}
 72	            policy={policy}
 73	            onClose={() => setModalOpen(false)}
 74	            onSubmit={(newPolicy) => {
 75	              setPolicy(newPolicy);
 76	              setModalOpen(false);
 77	            }}
 78	          />
 79	          <FormGroup fieldId="text">
 80	            <Text>
 81	              <Trans t={t} ns="plugin__nmstate-console-plugin">
 82	                Node network is configured and managed by NM state. Create a node network
 83	                configuration policy to describe the requested network configuration on your nodes
 84	                in the cluster. The node network configuration enactment reports the netwrok
 85	                policies enacted upon each node.
 86	              </Trans>
 87	            </Text>
 88	          </FormGroup>
 89	          <FormGroup fieldId="apply-selector">
 90	            <ApplySelectorCheckbox
 91	              isChecked={!!policy?.spec.nodeSelector}
 92	              onChange={(_, checked) => {
 93	                if (checked) setModalOpen(true);
 94	                else
 95	                  setPolicy((draftPolicy) => {
 96	                    delete draftPolicy.spec.nodeSelector;
 97	                  });
 98	              }}
 99	            />
100	          </FormGroup>
101	        </>
102	      )}
103	      <FormGroup label={t('Policy name')} isRequired fieldId="policy-name-group">
104	        <TextInput
105	          isRequired
106	          type="text"
107	          id="policy-name"
108	          name="policy-name"
109	          value={policy?.metadata?.name}
110	          isDisabled={!createForm}
111	          onChange={(_, newName) =>
112	            setPolicy((draftPolicy) => {
113	              draftPolicy.metadata.name = newName;
114	            })
115	          }
116	        />
117	      </FormGroup>
118	      <FormGroup label={t('Description')} fieldId="policy-description-group">
119	        <TextInput
120	          type="text"
121	          id="policy-description"
122	          name="policy-description"
123	          value={policy?.metadata?.annotations?.description}
124	          onChange={(_, newValue) => onDescriptionChange(newValue)}
125	        />
126	      </FormGroup>
127	      <div>
128	        <Text className="pf-u-primary-color-100 pf-u-font-weight-bold pf-u-font-size-lg">
129	          {t('Policy Interface(s)')}{' '}
130	          <Popover
131	            aria-label={'Help'}
132	            bodyContent={t(
133	              'List of network interfaces that should be created, modified, or removed, as a part of this policy.',
134	            )}
135	          >
136	            <HelpIcon />
137	          </Popover>
138	        </Text>
139	        <Text className="policy-form-content__add-new-interface pf-u-mt-md">
140	          <Button
141	            className="pf-m-link--align-left pf-u-ml-md"
142	            onClick={addNewInterface}
143	            type="button"
144	            variant="link"
145	          >
146	            <PlusCircleIcon />{' '}
147	            <span className="pf-u-ml-sm">{t('Add another interface to the policy')}</span>
148	          </Button>
149	        </Text>
150	        <PolicyInterfacesExpandable policy={policy} setPolicy={setPolicy} createForm={createForm} />
151	      </div>
152	      {isOVSBridge && <PolicyFormOVSBridgeMapping policy={policy} setPolicy={setPolicy} />}
153	    </Form>
154	  );
155	};
156	
157	export default PolicyForm;

